div.p:
c
u16 actual_offset = fragment.offset * 8;
if (actual_offset == buffer.expected_ptr) {
copy_to_buffer(buffer, fragment.data, fragment.len);
buffer.expected_ptr += fragment.len;
if (fragment.MF == 0) {
dispatch_to_upper_layer(buffer);
}
} else {
queue_out_of_order(fragment);
check_for_gaps();
}
